import React, { Component } from "react";
import $ from "jquery";
import "./App.scss";
import Header from "./components/Header";
import Footer from "./components/Footer";
import About from "./components/About";
import Experience from "./components/Experience";
import Projects from "./components/Projects";
import Skills from "./components/Skills";
import { motion } from "framer-motion";

class App extends Component {
  constructor(props) {
    super();
    this.state = {
      foo: "bar",
      resumeData: {},
      sharedData: {},
      activeLanguage: window.$primaryLanguage 
    };
  }

  applyPickedLanguage(pickedLanguage) {
    // 1. Update React state immediately
    this.setState({ activeLanguage: pickedLanguage });

    // 2. Update document language
    document.documentElement.lang = pickedLanguage;

    // 3. Determine which JSON to load
    var resumePath =
      document.documentElement.lang === window.$primaryLanguage
        ? `res_primaryLanguage.json`
        : `res_secondaryLanguage.json`;

    this.loadResumeFromPath(resumePath);
  }

  // We are keeping this function empty to prevent errors if other parts of the app call it,
  // but we are removing the manual 'filter' logic that was causing the darkness.
  swapCurrentlyActiveLanguage() {
    return; 
  }

  componentDidMount() {
    this.loadSharedData();
    this.applyPickedLanguage(window.$primaryLanguage);
  }

  loadResumeFromPath(path) {
    $.ajax({
      url: path,
      dataType: "json",
      cache: false,
      success: function (data) {
        this.setState({ resumeData: data });
      }.bind(this),
      error: function (xhr, status, err) {
        console.error("Error loading resume:", err);
      },
    });
  }

  loadSharedData() {
    $.ajax({
      url: `portfolio_shared_data.json`,
      dataType: "json",
      cache: false,
      success: function (data) {
        this.setState({ sharedData: data });
        document.title = data.basic_info.name;
      }.bind(this),
      error: function (xhr, status, err) {
        console.error("Error loading shared data:", err);
      },
    });
  }

  render() {
    return (
      <div>
        <Header sharedData={this.state.sharedData.basic_info} />

        <div className="col-md-12 mx-auto text-center language" style={{ padding: "40px 0" }}>

          {/* UK Flag */}
          <motion.div
            onClick={() => this.applyPickedLanguage(window.$primaryLanguage)}
            style={{ 
              display: "inline-block", 
              cursor: "pointer", 
              margin: "0 25px"
            }}
            whileHover={{ scale: 1.2 }}
            whileTap={{ scale: 0.9 }}
            animate={{
              filter: this.state.activeLanguage === window.$primaryLanguage 
                ? "brightness(1.2) drop-shadow(0px 0px 8px rgba(233,213,161,0.5))" 
                : "brightness(0.6) grayscale(0.5)",
              opacity: this.state.activeLanguage === window.$primaryLanguage ? 1 : 0.6
            }}
            transition={{ duration: 0.3 }}
          >
            <span
              className="iconify language-icon"
              data-icon="twemoji-flag-for-flag-united-kingdom"
              data-inline="false"
              style={{ fontSize: "50px" }}
            ></span>
          </motion.div>

          {/* India Flag */}
          <motion.div
            onClick={() => this.applyPickedLanguage(window.$secondaryLanguage)}
            style={{ 
              display: "inline-block", 
              cursor: "pointer", 
              margin: "0 25px"
            }}
            whileHover={{ scale: 1.2 }}
            whileTap={{ scale: 0.9 }}
            animate={{
              filter: this.state.activeLanguage === window.$secondaryLanguage 
                ? "brightness(1.2) drop-shadow(0px 0px 8px rgba(233,213,161,0.5))" 
                : "brightness(0.6) grayscale(0.5)",
              opacity: this.state.activeLanguage === window.$secondaryLanguage ? 1 : 0.6
            }}
            transition={{ duration: 0.3 }}
          >
            <span
              className="iconify language-icon"
              data-icon="twemoji-flag-for-flag-india"
              data-inline="false"
              style={{ fontSize: "50px" }}
            ></span>
          </motion.div>
        </div>

        <About
          resumeBasicInfo={this.state.resumeData.basic_info}
          sharedBasicInfo={this.state.sharedData.basic_info}
        />
        <Projects
          resumeProjects={this.state.resumeData.projects}
          resumeBasicInfo={this.state.resumeData.basic_info}
        />
        <Skills
          sharedSkills={this.state.sharedData.skills}
          resumeBasicInfo={this.state.resumeData.basic_info}
        />
        <Experience
          resumeExperience={this.state.resumeData.experience}
          resumeBasicInfo={this.state.resumeData.basic_info}
        />
        <Footer sharedBasicInfo={this.state.sharedData.basic_info} />
      </div>
    );
  }
}

export default App;
